import sailpoint.object.Identity;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  

  Log logger = LogFactory.getLog("rule.creation.Amita");

  logger.debug("rule.creation.Amita Entering");
  //generate samAccountName
  
  String samAccountName = initialUserName();
  if(Util.isNotNullOrEmpty(samAccountName))
  {
    identity.setName(samAccountName);
  }
  identity.setAttribute("authSourceAppName", application.getName()) ;
  logger.debug("rule.creation.Amita Exiting");
